COZE_COMBINE_CODE_175205 = 'import json\n\ndef dedupe_image_urls(urls):\n    if urls is None:\n        return []\n    if isinstance(urls, str):\n        u = urls.strip()\n        urls = [u] if u else []\n    elif not isinstance(urls, (list, tuple)):\n        return []\n    out = []\n    seen = set()\n    for item in urls:\n        if isinstance(item, dict):\n            item = item.get(\'image_url\') or item.get(\'url\') or item.get(\'src\') or \'\'\n        u = str(item or \'\').strip()\n        if not u or u in seen:\n            continue\n        out.append(u)\n        seen.add(u)\n    return out\n\ndef pick_next_image(pool, pointer, last_image):\n    if not pool:\n        return \'\', pointer\n    for i in range(len(pool)):\n        idx = (pointer + i) % len(pool)\n        candidate = pool[idx]\n        if candidate != last_image or len(pool) == 1:\n            return candidate, idx + 1\n    return pool[pointer % len(pool)], pointer + 1\n\nasync def main(args: Args) -> Output:\n    params = getattr(args, "params", None) or {}\n    cover_image = params.get(\'pic\') or params.get(\'bg_pic\')\n    bg_image = params.get(\'bg_pic\') or cover_image\n    audio_duration = params.get(\'audio_duration\', 0)\n    toptitle = params.get(\'toptitle\', \'\')\n    width = params.get(\'width\', 1920)\n    height = params.get(\'height\', 1080)\n    pre_time = params.get(\'pre_time\', 0)\n    title = params.get(\'title\', \'\')\n    bgm = params.get(\'bgm\', \'\')\n    scene_images = params.get(\'image_list\')\n    if scene_images is None:\n        scene_images = []\n    elif isinstance(scene_images, str):\n        u = scene_images.strip()\n        scene_images = [u] if u else []\n    elif not isinstance(scene_images, (list, tuple)):\n        scene_images = []\n    audios = params.get(\'audio_list\')\n    if not isinstance(audios, (list, tuple)):\n        audios = []\n    aud = int(audio_duration or 0)\n    intro_duration = aud + 200000\n    if len(audios) > 1:\n        s_body = int(audios[1].get(\'start\', intro_duration))\n        if s_body > 0:\n            intro_duration = s_body\n\n    title_captions = []\n    topcaptions = []\n\n    bgm_audios = []\n    if bgm:\n        bgm_audios.append({\n            \'audio_url\': bgm,\n            \'duration\': pre_time,\n            \'start\': 0,\n            \'end\': pre_time\n        })\n\n    # 翻书音效配置\n    _flip_sfx_url = \'https://houht.oss-cn-shanghai.aliyuncs.com/public/booklist/book.MP3\'\n    _flip_sfx_dur = 300000  # 每次翻书音效 0.3 秒\n    # 敲钟音效：标题出现时播放\n    _bell_sfx_url = \'https://houht.oss-cn-shanghai.aliyuncs.com/public/booklist/book.MP3\'\n    _bell_sfx_dur = 1500000  # 敲钟音效 1.5 秒\n\n    _intro_str = str(params.get(\'intro_image_list\') or \'\')\n    _intro_raw = params.get(\'intro_image_list\')\n    if isinstance(_intro_raw, (list, tuple)):\n        _intro_pool = dedupe_image_urls(_intro_raw)\n    elif isinstance(_intro_raw, str):\n        _intro_pool = dedupe_image_urls([u.strip() for u in _intro_raw.split(\'。\') if u.strip()])\n    else:\n        _intro_pool = []\n    if not _intro_pool:\n        _intro_pool = [cover_image] if cover_image else []\n\n    # 香烟式横向滑动轮播（V9效果）\n    # 延长轮播时间5秒\n    intro_duration = int(intro_duration) + 5000000\n    _reveal_start = int(intro_duration) - 2000000  # 最后2秒显示主神\n\n    # 所有图片同时存在，通过 carousel_imgs + KFTypePositionX 关键帧横向移动\n    # imgs1 只放背景图（由 bg_imgs 处理）和主神揭示图\n    imgs1 = []\n    if cover_image:\n        imgs1.append({\n            \'image_url\': cover_image,\n            \'width\': 768,\n            \'height\': 1024,\n            \'start\': _reveal_start,\n            \'end\': int(intro_duration),\n            \'in_animation\': \'\\u7f29\\u5c0f\',\n            \'in_animation_duration\': 600000,\n        })\n\n    # carousel_imgs: 16张图（8张重复两遍），每张有不同的 transform_x 起始位置\n    # 通过关键帧让它们同时横向滑动\n    _double_pool = (_intro_pool + _intro_pool)[:16]\n    _carousel_duration = int(intro_duration) - 2000000  # 轮播持续到主神出现前\n    carousel_imgs = []\n    for _ci, _curl in enumerate(_double_pool):\n        _x_pos = -7500 + _ci * 1000  # 间距1000\n        carousel_imgs.append({\n            \'image_url\': _curl,\n            \'width\': 768,\n            \'height\': 1024,\n            \'start\': 0,\n            \'end\': _carousel_duration,\n            \'transform_x\': _x_pos,\n        })\n    # 翻书音效：每张图切换时不再需要（横向滑动没有翻页）\n    # 敲钟音效：主神出现时触发\n    bgm_audios.append({\n        \'audio_url\': _bell_sfx_url,\n        \'duration\': _bell_sfx_dur,\n        \'start\': _reveal_start,\n        \'end\': _reveal_start + _bell_sfx_dur,\n    })\n    # 标题字幕：主神出现时才显示\n    title_captions = [{\n        \'text\': title,\n        \'start\': _reveal_start,\n        \'end\': int(intro_duration),\n        \'in_animation\': \'\\u7f29\\u5c0f\',\n        \'in_animation_duration\': 600000,\n    }]\n    # 顶部标签：轮播期间显示\n    topcaptions = [{\n        \'text\': toptitle,\n        \'start\': 0,\n        \'end\': _reveal_start,\n        \'in_animation\': \'\\u6e10\\u663e\',\n        \'in_animation_duration\': 600000,\n    }]\n\n    # 背景图层单独输出（由独立节点添加，不接关键帧，静态不动）\n    bg_imgs = []\n    if bg_image:\n        bg_imgs.append({\n            \'image_url\': bg_image,\n            \'width\': width,\n            \'height\': height,\n            \'start\': 0,\n            \'end\': int(pre_time),\n        })\n\n    imgs2 = []\n\n    _csl_spacing = 700\n    carousel_imgs = []\n\n    scene_pool = dedupe_image_urls(scene_images)\n    if not scene_pool:\n        scene_pool = dedupe_image_urls([bg_image, cover_image])\n\n    focus_imgs = []\n    focus_captions = []\n    focus_dim_captions = []\n\n    if scene_pool:\n        scene_audios = audios[1:] if len(audios) > 1 else []\n        fallback_image = scene_pool[0] if scene_pool else (bg_image or cover_image)\n        image_index = 0\n        last_image = None\n        slot_us = 3000000\n        _scene_anim_idx = 0\n\n        for audio_obj in scene_audios:\n            segment_start = int(audio_obj.get(\'start\', intro_duration))\n            segment_end = int(audio_obj.get(\'end\', intro_duration))\n            if segment_end <= segment_start:\n                continue\n            t = segment_start\n            while t < segment_end:\n                chunk_end = min(segment_end, t + slot_us)\n                if chunk_end <= t:\n                    break\n                candidate, image_index = pick_next_image(scene_pool, image_index, last_image)\n                image_url = candidate or fallback_image\n                last_image = image_url\n                fallback_image = image_url or fallback_image\n\n                # 每换一张图，切换一种入场动画\n                _anim_pool = [\'\\u6e10\\u663e\', \'\\u7f29\\u5c0f\', \'\\u5411\\u5de6\\u6ed1\\u52a8\', \'\\u5411\\u53f3\\u6ed1\\u52a8\', \'\\u6a21\\u7cca\\u51fa\\u73b0\']\n                _anim_name = _anim_pool[_scene_anim_idx % len(_anim_pool)]\n                _scene_anim_idx += 1\n\n                seg_len = max(chunk_end - t, 1)\n                piece_count = 3 if seg_len >= 3200000 else (2 if seg_len >= 1600000 else 1)\n                piece_duration = max(seg_len // piece_count, 380000)\n                cursor = t\n                for piece_idx in range(piece_count):\n                    piece_end = chunk_end if piece_idx == piece_count - 1 else min(chunk_end, cursor + piece_duration)\n                    if piece_end <= cursor:\n                        continue\n\n                    motion = {\n                        \'scale_x\': 1.0,\n                        \'scale_y\': 1.0,\n                        \'transform_x\': 0.0,\n                        \'transform_y\': 0.0\n                    }\n\n                    # 交替使用不同入场动画，让画面不死板\n                    _anim_dur = min(800000, max(piece_end - cursor, 400000))\n\n                    scene_img = {\n                        \'image_url\': image_url or bg_image,\n                        \'width\': width,\n                        \'height\': height,\n                        \'start\': cursor,\n                        \'end\': piece_end,\n                        \'in_animation\': _anim_name,\n                        \'in_animation_duration\': _anim_dur,\n                    }\n                    scene_img.update(motion)\n                    imgs2.append(scene_img)\n                    cursor = piece_end\n                t = chunk_end\n    else:\n        imgs2.append({\n            \'image_url\': bg_image,\n            \'width\': width,\n            \'height\': height,\n            \'start\': intro_duration,\n            \'end\': pre_time\n        })\n\n    i0 = int(intro_duration)\n    p0 = int(pre_time)\n    q_intro = max(i0 // 4, 1)\n    effects = []\n    intro_specs = [\n        (\'\\u5149\\u6655\', 0, min(max(q_intro // 2, 1), i0)),\n        (\'\\u6a21\\u7cca\', 0, min(q_intro, i0)),\n        (\'\\u53d1\\u5149\', min(q_intro, i0), min(2 * q_intro, i0)),\n        (\'\\u6697\\u89d2\', min(2 * q_intro, i0), min(3 * q_intro, i0)),\n        (\'\\u9897\\u7c92\', min(3 * q_intro, i0), i0),\n        (\'\\u67d4\\u5149\', 0, i0),\n    ]\n    for _tit, _s, _e in intro_specs:\n        if _e > _s:\n            effects.append({\'effect_title\': _tit, \'start\': _s, \'end\': _e})\n\n    span_body = max(p0 - i0, 1)\n    q_body = max(span_body // 6, 1)\n    body_specs = [\n        \'\\u661f\\u706b\',\n        \'\\u91d1\\u7c89\',\n        \'\\u67d4\\u5149\',\n        \'\\u5149\\u6655\',\n        \'\\u68a6\\u5e7b\',\n        \'\\u95ea\\u767d\',\n        \'\\u6d53\\u96fe\',\n    ]\n    effects2 = []\n    for _k, _tit in enumerate(body_specs):\n        _s = i0 + min(_k * q_body, span_body)\n        _e = p0 if _k >= len(body_specs) - 1 else i0 + min((_k + 1) * q_body, p0)\n        if _e > _s:\n            effects2.append({\'effect_title\': _tit, \'start\': _s, \'end\': _e})\n    if p0 > i0:\n        _gs = i0 + span_body // 3\n        _ge = min(i0 + 2 * span_body // 3, p0)\n        if _ge > _gs:\n            effects2.append({\'effect_title\': \'\\u53d1\\u5149\', \'start\': _gs, \'end\': _ge})\n\n    _csl_singles_list = []\n    _csl_positions_list = []\n    _csl_values_list = []\n    for _cimg in carousel_imgs:\n        _csingle = {k: v for k, v in _cimg.items() if k != \'transform_x\'}\n        _csl_singles_list.append(json.dumps([_csingle]))\n        _pos = int(_cimg.get(\'transform_x\', 0))\n        _csl_positions_list.append(str(_pos))\n        # 关键帧：从起始位置匀速滑到终止位置（不回来）\n        _end_pos = _pos + 16000\n        _csl_values_list.append(f\'{_pos}|{_end_pos}\')\n\n    return {\n        \'captions\': json.dumps(params.get(\'caption_list\') or []),\n        \'audios\': json.dumps(audios),\n        \'bgm_audios\': json.dumps(bgm_audios),\n        \'imgs1\': json.dumps(imgs1),\n        \'imgs2\': json.dumps(imgs2),\n        \'bg_imgs\': json.dumps(bg_imgs),\n        \'carousel_imgs\': json.dumps(carousel_imgs),\n        \'focus_imgs\': json.dumps(focus_imgs),\n        \'focusCaptions\': json.dumps(focus_captions),\n        \'focusDimCaptions\': json.dumps(focus_dim_captions),\n        \'effects\': json.dumps(effects),\n        \'effects2\': json.dumps(effects2),\n        \'titleCaptions\': json.dumps(title_captions),\n        \'topcaptions\': json.dumps(topcaptions),\n        \'csl_singles\': \'。\'.join(_csl_singles_list),\n        \'csl_positions\': \'。\'.join(_csl_positions_list),\n        \'csl_values\': \'。\'.join(_csl_values_list),\n        \'intro_urls\': json.dumps([img[\'image_url\'] for img in imgs1]),\n        \'intro_timelines\': json.dumps([{\'start\': img[\'start\'], \'end\': img[\'end\']} for img in imgs1]),\n        \'progress_imgs\': json.dumps([{\'image_url\': \'https://free.boltp.com/2026/05/04/69f8123eb20f5.webp\', \'width\': 1, \'height\': 1, \'start\': 0, \'end\': 1000000, \'alpha\': 0}]),\n    }\n'
